head.script:
/*세관 반입신고 등록 */

//hidden
scwin.txtDocCd = 0;
scwin.txtChgClsCd = 0;
scwin.txtDeclarNo = 0;
scwin.txtCnt = 0;
scwin.txtWt = 0;
scwin.txt_cntrBulk = "";

//Date
scwin.strFromDate = $c.date.getServerDateTime("yyyyMMdd").substring(0, 8);   // 현재년월일을 구한다.
scwin.strToDate = $c.date.getServerDateTime("yyyyMMdd");                    // 현재년월일을 구한다.
scwin.strDate = scwin.strFromDate + scwin.strToDate;

scwin.initCnt = 0;
scwin.isOpenRetrieve = false;

scwin.onpageload = function () {
    const codeOptions = [
        { grpCd: "OP132", compID: "gr_retrieve:crryinoutAccdPattern", opt: { "range": "1" } },
        { grpCd: "OP135", compID: "gr_retrieve:divsCrryinoutClsCd", opt: { "range": "1" } },
        { grpCd: "OP145", compID: "gr_retrieve:crryinPurpsCls", opt: { "range": "1" } },
        { grpCd: "OP498", compID: "gr_retrieve:xrayClsCd", opt: { "range": "1" } },
        { grpCd: "SD116", compID: "gr_retrieve:crryinPackKnd", opt: { "range": "1" } },
    ];

    $c.data.setCommonCode(codeOptions, scwin.onLoadCommonCode);

    preRetrieve.setValue("");

    $c.gus.cfDisableBtnOnly([btn_save, btn_delete]);
    $c.gus.cfDisableObjects([tb_retrieveData]);

    chb_printCheck.setValue("1");
    chb_previewCheck.setValue("1");
    chb_printCheck1.setValue("1");
    chb_previewCheck1.setValue("1");
    grp_perf_info.setReadOnly(true);
    scwin.chkInit();
};

scwin.onUdcCompleted = function () {
    scwin.chkInit();
};

scwin.onLoadCommonCode = function () {
    scwin.chkInit();
};

scwin.chkInit = function () {
    if (++scwin.initCnt >= 3) {
        scwin.init();
    }
};

scwin.init = function () {
    let params = $c.data.getParameter();
    if ("" != params?.odrNo && "1" == params?.openFlag) { //다른 페이지에서 넘어왔을 때
        scwin.f_OpenRetrieve();
    }
};

//-------------------------------------------------------------------------
// 세관반출입현황에서 조회
//-------------------------------------------------------------------------
scwin.f_OpenRetrieve = function () {
    let params = $c.data.getParameter();
    let cfsCls = params?.cfsCls ?? "";
    let wrkPlCd = params?.wrkPlCd ?? "";
    let wrkPlNm = params?.wrkPlNm ?? "";
    let mrn = params?.mrn ?? "";
    let msn = params?.msn ?? "";
    let hsn = params?.hsn ?? "";
    let blNo = params?.blNo ?? "";
    let odrNo = params?.odrNo ?? "";
    let cntrBulk = params?.cntrBulk ?? "";

    ed_wrkPlCd.setValue(wrkPlCd);
    ed_wrkPlNm.setValue(wrkPlNm);
    ed_mrn.setValue(mrn);
    ed_msn.setValue(msn);
    ed_hsn.setValue(hsn);
    ed_blNo.setValue(blNo);
    ed_odrNo.setValue(odrNo);

    if (cfsCls == "") {
        preRetrieve.setValue("1");
    }

    dma_condition.set("wrkPlCd", wrkPlCd);
    dma_condition.set("mrn", mrn);
    dma_condition.set("msn", ed_msn.getValue() == "" ? -1 : ed_msn.getValue());
    dma_condition.set("hsn", ed_hsn.getValue() == "" ? -1 : ed_hsn.getValue());
    dma_condition.set("blNo", blNo);
    dma_condition.set("odrNo", odrNo);
    dma_condition.set("cntrBulk", cntrBulk);

    if (cfsCls == "") {
        dma_condition.set("preRetrieve", "1");
    } else {
        dma_condition.set("preRetrieve", "0");
    }

    scwin.isOpenRetrieve = true;
    $c.sbm.execute(sbm_retrieve);
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------

//삭제
scwin.f_Del = async function () {
    let cnt = 0;
    if (ds_retrieve.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_001, ["Data"]);
        return;
    }

    for (i = 0; i < ds_retrieve.getRowCount(); i++) {
        if (ds_retrieve.getRowStatusValue(i) == "1") { //갱신
            if (ds_retrieve.getCellData(i, "che") == 1) {
                cnt++;
            }
        }
    }

    if (cnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["항목"]);
        return;
    }

    if (await $c.win.confirm("정말 삭제하시겠습니까?")) {
        $c.sbm.execute(sbm_saveDel);
    }
};

//전송
scwin.f_Send = async function () {
    let k = 0;
    let sndClsCd = "0";
    //변경한 데이터가 있는지 체크한다.
    if (ds_retrieve.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_001, ["Data"]);
        return;
    }

    // 필수항목 체크
    if (!await $c.gus.cfValidate([gr_retrieve], null, true)) {
        return;
    }

    if (await $c.win.confirm("저장하시겠습니까?")) {
        for (i = 0; i < ds_retrieve.getRowCount(); i++) {
            if (ds_retrieve.getRowStatusValue(i) == "1") { //갱신
                if (ds_retrieve.getCellData(i, "che") == 1) {
                    k++;
                    //황창기 추가 반입일시 날짜형식틀리면 조회할때 에러남
                    if (!$c.date.isDate(ds_retrieve.getCellData(i, "crryinoutDtm"), true)) {
                        await $c.gus.cfAlertMsg("날짜형식이 잘못되었습니다. 다시 입력하여주세요");
                        return;
                    }

                    //grid - 반입유형
                    if (ds_retrieve.getCellData(i, "crryinoutPatternCd") == "20"
                        || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "21"
                        || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "22"
                        || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "24"
                        || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "31") {

                        //grid - 반입근거번호
                        if (ds_retrieve.getCellData(i, "crryinoutBasisNo") == "") {
                            $c.win.alert("반입근거번호를 넣어주세요");
                            gr_retrieve.setFocusedCell(i, "crryinoutBasisNo", true)
                            return;
                        }
                    }

                    if (ds_retrieve.getCellData(i, "crryinoutPatternCd") == "10"
                        || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "11"
                        || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "23"
                        || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "40") {

                        if (ds_retrieve.getCellData(i, "crryinoutBasisNo") != "") {
                            $c.win.alert("반입근거번호를 지워주세요");
                            gr_retrieve.setFocusedCell(i, "crryinoutBasisNo", true)
                            return;
                        }
                    }

                    if (ds_retrieve.getCellData(i, "crryinoutPatternCd") == "16") {
                        if (ds_retrieve.getCellData(i, "tankNo") == "") {
                            $c.win.alert("수출물품 환적 입항반입신고는 탱크번호를 입력해주세요");
                            gr_retrieve.setFocusedCell(i, "tankNo", true)
                            return;
                        }
                    }

                    sndClsCd = "0"; // 전송구분코드

                    ds_retrieve.setCellData(i, "sndClsCd", sndClsCd);
                }
            } else if (ds_retrieve.getRowStatusValue(i) == "3") {//삭제
                k++;
            }
        }

        if (k == 0) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["항목"]);
            return;
        }

        $c.sbm.execute(sbm_save);
    }
};

//저장
scwin.f_Save = async function (val) {
    let k = 0;
    let sndClsCd = "0";

    //변경한 데이터가 있는지 체크한다.
    if (ds_retrieve.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_001, ["Data"]);
        return;
    }

    // 필수항목 체크
    if (!await $c.gus.cfValidate([gr_retrieve], null, true)) {
        return;
    }

    if (!await $c.win.confirm("저장하시겠습니까?")) {
        return;
    }

    for (i = 0; i < ds_retrieve.getRowCount(); i++) {
        if (ds_retrieve.getRowStatusValue(i) == "1") { //갱신신
            if (ds_retrieve.getCellData(i, "che") == 1) {
                k++;
                //황창기 추가 반입일시 날짜형식틀리면 조회할때 에러남
                if (!$c.date.isDate(ds_retrieve.getCellData(i, "crryinoutDtm"), true)) {
                    await $c.gus.cfAlertMsg("날짜형식이 잘못되었습니다. 다시 입력하여주세요");
                    return;
                }

                //grid - 반입유형
                if (ds_retrieve.getCellData(i, "crryinoutPatternCd") == "20"
                    || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "21"
                    || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "22"
                    || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "24"
                    || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "31") {

                    //grid - 반입근거번호
                    if (ds_retrieve.getCellData(i, "crryinoutBasisNo") == "") {
                        $c.win.alert("반입근거번호를 넣어주세요");
                        gr_retrieve.setFocusedCell(i, "crryinoutBasisNo", true)
                        return;
                    }
                }

                if (ds_retrieve.getCellData(i, "crryinoutPatternCd") == "10"
                    || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "11"
                    || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "23"
                    || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "40") {

                    if (ds_retrieve.getCellData(i, "crryinoutBasisNo") != "") {
                        $c.win.alert("반입근거번호를 지워주세요");
                        gr_retrieve.setFocusedCell(i, "crryinoutBasisNo", true)
                        return;
                    }
                }

                if (ds_retrieve.getCellData(i, "crryinoutPatternCd") == "16") {
                    if (ds_retrieve.getCellData(i, "tankNo") == "") {
                        $c.win.alert("수출물품 환적 입항반입신고는 탱크번호를 입력해주세요");
                        gr_retrieve.setFocusedCell(i, "tankNo", true)
                        return;
                    }
                }

                sndClsCd = ds_retrieve.getCellData(i, "sndClsCd");

                ds_retrieve.setCellData(i, "sndClsCd", sndClsCd);

            }
        } else if (ds_retrieve.getRowStatusValue(i) == "3") {
            k++;
        }
    }

    if (k == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["항목"]);
        return;
    }

    $c.sbm.execute(sbm_save);
};

scwin.cntWtCheck = function (row) {
    if (scwin.txtDeclarNo != "") {
        if (scwin.txtCnt == 0 && scwin.txtWt == 0) {
            ds_retrieve.setCellData(row, "divsCrryinoutClsCd", "L");
            return true;
        }

        if (scwin.txtCnt < 0 || scwin.txtWt < 0) {
            $c.win.alert("B/L 물량보다 OVER합니다.");
            return false;
        }

        if (scwin.txtCnt > 0 && scwin.txtWt > 0) {
            ds_retrieve.getCellData(row, "divsCrryinoutClsCd", "P");
            return true;
        }

        if ((scwin.txtCnt == 0 && scwin.txtWt > 0) || (scwin.txtCnt > 0 && scwin.txtWt == 0)) {
            $c.win.alert("B/L 물량보다 OVER합니다.");
            return false;
        }
    } else {
        if (scwin.txtCnt < 0 || scwin.txtWt < 0) {
            $c.win.alert("B/L 물량보다 OVER합니다.");
            return false;
        }

        if (scwin.txtCnt == 0 && scwin.txtWt == 0) {
            ds_retrieve.setCellData(row, "divsCrryinoutClsCd", "A");
            return true;
        }

        if (scwin.txtCnt > 0 && scwin.txtWt > 0) {
            ds_retrieve.setCellData(row, "divsCrryinoutClsCd", "P");
            return true;
        }

        if ((scwin.txtCnt == 0 && scwin.txtWt > 0) || (scwin.txtCnt > 0 && scwin.txtWt == 0)) {
            $c.win.alert("B/L 물량보다 OVER합니다.");
            return false;
        }
    }
};

