scwin.f_Print2 = function () {
    // 필수항목 체크
    // if (!await $c.gus.cfValidate(tb_queryList)) {
    //     return;
    // }

    // // 리포트(OZR)에 적용할 파라미터를 설정(OZFormParam)
    // let odiParam = new ODIParam("op_302_01_17r");
    // odiParam.add("MRN", ds_retrieve.getCellData(ds_retrieve.RowPosition, "mrn"));
    // odiParam.add("MSN", ds_retrieve.getCellData(ds_retrieve.RowPosition, "msn"));
    // odiParam.add("HSN", ds_retrieve.getCellData(ds_retrieve.RowPosition, "hsn"));

    // let formParam = new FormParam();

    // // OZ 뷰어에 대한 설정(상세 설정은 'oz report viewer guide.pdf'를 참조)
    // let viewerParam = new ViewerParam();
    // viewerParam.add("viewer.zoom", "100");

    // $c.gus.cfOZReport("chb_printCheck", "chb_previewCheck", "/ds/op/wrkrslts/yardwrkrslts/op_302_01_17r.ozr", odiParam, viewerParam, formParam);

    let reportFile = "/ds/op/wrkrslts/yardwrkrslts/op_302_01_17r.ozr";
    let odiName = "op_302_01_17r";
    let mode = "";

    let rowpo = ds_retrieve.getRowPosition();

    let odiParam = {
        "MRN": ds_retrieve.getCellData(rowpo, "mrn"),
        "MSN": ds_retrieve.getCellData(rowpo, "msn"),
        "HSN": ds_retrieve.getCellData(rowpo, "hsn")
    }

    if (chb_previewCheck.getValue() == "1") {
        mode = "preview";
    } else if (chb_printCheck.getValue() == "1") {
        mode = "print";
    }

    let data = {
        odiName: odiName,
        reportName: reportFile,
        odiParam: odiParam,
        viewerParam: {
            "useprogressbar": true, // 프로그레스바 쓸지 말지
            "mode": mode,
        },
        formParam: {
        }
    };

    if (chb_previewCheck.getValue() == "1") { // 미리보기 체크된 경우
        let opts = {
            id: "ozReportPopup",
            popupName: "오즈 리포트",
            modal: false,
            type: "browserPopup",
            width: 1000,
            height: 830,
            title: "오즈 리포트"
        };

        $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
    } else if (chb_printCheck.getValue() == "1") { // 인쇄옵션 체크된 경우
        let opts = {
            type: 'print', // viewer, print, download
            printMode: 'view', // silent, view
        }
        $c.ext.printOzReport(data, opts);
    } else { // 저장후바로출력
        let opts = {
            filename: odiName,
            exportMode: 'view'
        }
        $c.ext.downloadOzReport(data, opts);
    }
};

//-------------------------------------------------------------------------
// 조회 조건 초기화
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects([ed_wrkPlCd, ed_wrkPlNm, ed_blNo, ed_mrn, ed_msn, ed_hsn, ed_odrNo]);
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }
    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true) {
        // inObj가 코드 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        // inObj가 코드명 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

//-------------------------------------------------------------------------
// 작업장 POP UP
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 작업장 팝업
    udc_comCodeWrkpl.cfCommonPopUp((rtnList) => $c.gus.cfSetReturnValue(rtnList, ed_wrkPlCd, ed_wrkPlNm)
        , pCode
        , pName
        , pClose
        , null
        , null
        , null
        , null
        , null
        , null
        , null
        , null
        , null
        , null
        , pAllSearch
        , "작업장,작업장코드,작업장명"
    );
};

