//-------------------------------------------------------------------------
// 반입신고번호 - 오류 상세내역 조회 팝업
//-------------------------------------------------------------------------
scwin.f_errorPopUp = async function (row) {
    //환적화물이고반입 오류시에도 오류상세내역 확인가능하게 수정
    let docCd = "";
    if (ds_retrieve.getCellData(row, 'crryinoutPatternCd') == '19') {
        docCd = "357";
    } else {
        docCd = "632";
    }

    let declarNo = ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "crryinoutDeclarNo");
    let deg = 0;

    let data = {
        deg: deg			// 화면에서의 ??? Code Element의	Value
        , docCd: docCd					// 화면에서의 ??? Name Element의	Value
        , declarNo: declarNo					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
    };

    let opts = {
        id: "Pop",
        popupName: "오류상세내역",
        modal: true,
        type: "browserPopup",
        width: 860,      // 가로 크기 (픽셀)
        height: 580,     // 세로 크기 (픽셀)
        title: "Win pop"
    };

    rtnList = await $c.win.openPopup("/ui/ds/sd/odrmgnt/odrprewrk/sd_401_05_04p.xml", opts, data);
};

scwin.cheValidate = function (info) {
    if (info.newValue == "1") {
        ed_mrn.setMandatory(true);
        ed_mrn.setUserData("validExp", "화물관리번호:yes");
        txt_mrn.addClass("req");
    } else {
        ed_mrn.setMandatory(false);
        ed_mrn.setUserData("validExp", "");
        txt_mrn.removeClass("req");
    }
};

