//조회
scwin.f_Retrieve = async function () {
    //필수체크 멘트 때문에 개별로 체크
    let chkwrkplcd = ed_wrkPlCd.getValue();
    if ($c.gus.cfIsNull(chkwrkplcd)) {
        await $c.win.alert("작업장 코드는 필수 입력 항목입니다.");
        ed_wrkPlCd.focus();
        return;
    }

    // 필수항목 체크
    if (!await $c.gus.cfValidate([tb_queryList], null, true)) {
        return;
    }

    if (ed_mrn.getValue() == "" && ed_blNo.getValue() == "" && ed_odrNo.getValue() == "" && crryinoutDtmFrom.getValue() == "") {
        $c.win.alert("MRN,BL번호,오더번호,일자 중 하나는 입력해야 합니다.");
        return;
    }

    if (preRetrieve.getValue() != 0) {
        if (ed_mrn.getValue() == "") {
            $c.win.alert("화물관리번호는 필수입니다.");
            return;
        }
    }

    if (!$c.gus.cfIsAfterDate(crryinoutDtmFrom.getValue(), crryinoutDtmTo.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        crryinoutDtmFrom.focus();
        return;
    }

    if (ed_mrn.getValue() != "") {
        if (ed_mrn.getValue().length < 11) {
            $c.win.alert("MRN은 11자리입니다");
            ed_mrn.focus();
            return;
        }
    }

    if (ed_odrNo.getValue() != "") {
        if (ed_odrNo.getValue().length < 13) {
            $c.win.alert("오더번호는 13자리입니다.");
            ed_odrNo.focus();
            return;
        }
    }

    let cheVal = "0";
    if (preRetrieve.getValue() != 0) {
        cheVal = "1";
    }

    dma_condition.set("wrkPlCd", ed_wrkPlCd.getValue());
    dma_condition.set("mrn", ed_mrn.getValue());

    let msn = ed_msn.getValue() == "" ? -1 : ed_msn.getValue()
    dma_condition.set("msn", msn);

    let hsn = ed_hsn.getValue() == "" ? -1 : ed_hsn.getValue()
    dma_condition.set("hsn", hsn);

    dma_condition.set("blNo", ed_blNo.getValue());
    dma_condition.set("odrNo", ed_odrNo.getValue());
    dma_condition.set("preRetrieve", cheVal);
    dma_condition.set("crryinoutDtmFrom", crryinoutDtmFrom.getValue());
    dma_condition.set("crryinoutDtmTo", crryinoutDtmTo.getValue());

    $c.sbm.execute(sbm_retrieve);

};

//조회결과 
scwin.sbm_retrieve_submitdone = async function (e) {
    totalRows.setValue(ds_retrieve.getRowCount());

    if (ds_retrieve.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        $c.gus.cfDisableBtnOnly([btn_trans, btn_save, btn_delete]);
    } else {
        if (ds_retrieve.getCellData(0, "newData") == 0) { //newData 없음 어차피
            $c.gus.cfEnableObj(btn_trans, false);
            $c.gus.cfEnableObj(btn_delete, false);
            $c.gus.cfEnableObj(btn_save, true);
        } else {
            $c.gus.cfEnableObj(btn_trans, true);
            $c.gus.cfEnableObj(btn_save, true);
            $c.gus.cfEnableObj(btn_delete, true);
        }

        if (scwin.isOpenRetrieve) {
            scwin.isOpenRetrieve = false;
            crryinoutDtmFrom.setValue(ds_retrieve.getCellData(0, "crryinoutDtm").substring(0, 8));
            crryinoutDtmTo.setValue(ds_retrieve.getCellData(0, "crryinoutDtm").substring(0, 8));
        }

        for (let i = 0; i < ds_retrieve.getRowCount(); i++) {
            if (ds_retrieve.getCellData(i, "crryinoutAccdPattern") == "") {
                ds_retrieve.setCellData(i, "crryinoutAccdPattern", "OKY");
            }

            if (ds_retrieve.getCellData(i, "crryinPurpsCls") == "") {
                ds_retrieve.setCellData(i, "crryinPurpsCls", "P");
            }
        }

        ds_retrieve.modifyAllStatus("R");
        gr_retrieve.setFocusedCell(0, gr_retrieve.getFocusedColumnID() ?? "che", false);
    }

    //실적정보 Setting
    ed_mblNo.setValue(ds_retrieve.getCellData(0, "mblNo"));
    ed_hblNo.setValue(ds_retrieve.getCellData(0, "hblNo"));
    ed_mcomDsmbrkPlcCd.setValue(ds_retrieve.getCellData(0, "mcomDsmbrkPlcCd"));
    ed_mcomDsmbrkPlNm.setValue(ds_retrieve.getCellData(0, "mcomDsmbrkPlcNm"));
    ed_packUnitCd.setValue(ds_retrieve.getCellData(0, "packUnitCd"));
    ed_packUnitNm.setValue(ds_retrieve.getCellData(0, "packUnitNm"));
    ed_odrNo2.setValue(ds_retrieve.getCellData(0, "odrNo"));
    ed_commCd.setValue(ds_retrieve.getCellData(0, "commCd"));
    ed_commNm.setValue(ds_retrieve.getCellData(0, "commNm"));
    ed_packCnt.setValue(ds_retrieve.getCellData(0, "packCnt"));
    ed_totWt.setValue(ds_retrieve.getCellData(0, "totWt"));
    ed_totCbm.setValue(ds_retrieve.getCellData(0, "totCbm"));
    ed_cnsgnNmCmpy.setValue(ds_retrieve.getCellData(0, "cnsgnNmCmpy"));
    ed_vsslNm.setValue(ds_retrieve.getCellData(0, "vsslNm"));
    ed_arrvlportDt.setValue(ds_retrieve.getCellData(0, "arrvlportDt"));

    let rowObj = null;
    //sndClsCd에 값이 0이면 gr_retrieve 그리드의 해당 로우 읽기 전용으로 변경 
    for (let idx = 0; idx < ds_retrieve.getRowCount(); idx++) {
        rowObj = ds_retrieve.getRowJSON(idx);
        if (rowObj.sndClsCd == "0") {
            gr_retrieve.setRowReadOnly(idx, true);
        } else if (rowObj.sndClsCd == "1") {
            if (rowObj.sndClsNm == "접수") {
                gr_retrieve.setRowReadOnly(idx, true);
            }
        }
        gr_retrieve.setCellReadOnly(idx, "crryinPurpsCls", false);
        gr_retrieve.setCellReadOnly(idx, "xrayClsCd", false);
        gr_retrieve.setCellReadOnly(idx, "tankNo", false);
    }
};

