scwin.gr_retrieve_onheaderclick = function (headerId) {
    let bCheck = "0";
    if (headerId == "checkYn") {
        bCheck = gr_retrieve.getHeaderValue("checkYn");
    }

    let chk = bCheck == 1 ? "1" : "0";
    let cr = ds_retrieve.getRowCount();
    if (headerId == "che") {
        if (chk == 1) {
            for (let i = 0; i < cr; i++) {
                if (ds_retrieve.getCellData(i, "sndClsCd") == "0") {
                    ds_retrieve.setCellData(i, "che", 0);
                } else if (ds_retrieve.getCellData(i, "sndClsCd") == "1") {
                    if (ds_retrieve.getCellData(i, "sndClsNm") == "접수") {
                        ds_retrieve.setCellData(i, "che", 0);
                    } else {
                        ds_retrieve.setCellData(i, "che", 1);
                    }
                } else {
                    ds_retrieve.setCellData(i, "che", 1);
                }
            }
        } else {
            for (let i = 0; i < cr; i++) {
                ds_retrieve.setCellData(i, "che", 0);
            }
        }
    }
};

scwin.ed_msn_onkeyup = function (e) {
    if (ed_msn.getValue().length == 4) {
        ed_hsn.focus();
        return;
    }
};

scwin.gr_retrieve_oncellclick = function (row, columnIndex, columnId) {
    if (columnId == "che") {
        if (ds_retrieve.getCellData(row, "sndClsCd") == "0") {
            $c.win.alert("이미 전송된 데이타입니다.");
            ds_retrieve.setCellData(row, "che", 0);
            return;
        } else if (ds_retrieve.getCellData(row, "sndClsCd") == "1") {
            if (ds_retrieve.getCellData(row, "sndClsNm") == "접수") {
                $c.win.alert("이미 전송된 데이타입니다.");
                ds_retrieve.setCellData(row, "che", 0);
                return;
            }
        }
    } else {
        //전송구분(hidden)
        if (ds_retrieve.getCellData(row, "sndClsCd") == "0") {
            //용도구분, Xray검사구분, 탱크번호 제외하고 readonly 걸기                    
            gr_retrieve.setReadOnly("cell", row, "mrn", true);
            gr_retrieve.setReadOnly("cell", row, "msn", true);
            gr_retrieve.setReadOnly("cell", row, "hsn", true);
            gr_retrieve.setReadOnly("cell", row, "divsCrryinoutClsCd", true);

            gr_retrieve.setReadOnly("cell", row, "crryinoutDtm", true);
            gr_retrieve.setReadOnly("cell", row, "crryinoutPatternCd", true);
            gr_retrieve.setReadOnly("cell", row, "crryinoutAccdPattern", true);
            gr_retrieve.setReadOnly("cell", row, "crryinoutBasisNo", true);
            gr_retrieve.setReadOnly("cell", row, "crryinoutCnt", true);

            gr_retrieve.setReadOnly("cell", row, "crryinoutWt", true);
            gr_retrieve.setReadOnly("cell", row, "crryinAccdCnt", true);
            gr_retrieve.setReadOnly("cell", row, "crryinAccdWt", true);
            gr_retrieve.setReadOnly("cell", row, "sndDtm", true);

            gr_retrieve.setReadOnly("cell", row, "sndClsNm", true);
            gr_retrieve.setReadOnly("cell", row, "dsmbrkBondZoneNm", true);
            gr_retrieve.setReadOnly("cell", row, "crryinPackKnd", true);
        } else if (ds_retrieve.getCellData(row, "sndClsCd") == "1") {
            //접수구분
            if (ds_retrieve.getCellData(row, "sndClsNm") == "접수" || ds_retrieve.getCellData(row, "sndClsNm") == "전송완료") {
                //용도구분, Xray검사구분, 탱크번호 제외하고 readonly 걸기                    
                gr_retrieve.setReadOnly("cell", row, "mrn", true);
                gr_retrieve.setReadOnly("cell", row, "msn", true);
                gr_retrieve.setReadOnly("cell", row, "hsn", true);
                gr_retrieve.setReadOnly("cell", row, "divsCrryinoutClsCd", true);

                gr_retrieve.setReadOnly("cell", row, "crryinoutDtm", true);
                gr_retrieve.setReadOnly("cell", row, "crryinoutPatternCd", true);
                gr_retrieve.setReadOnly("cell", row, "crryinoutAccdPattern", true);
                gr_retrieve.setReadOnly("cell", row, "crryinoutBasisNo", true);
                gr_retrieve.setReadOnly("cell", row, "crryinoutCnt", true);

                gr_retrieve.setReadOnly("cell", row, "crryinoutWt", true);
                gr_retrieve.setReadOnly("cell", row, "crryinAccdCnt", true);
                gr_retrieve.setReadOnly("cell", row, "crryinAccdWt", true);
                gr_retrieve.setReadOnly("cell", row, "sndDtm", true);

                gr_retrieve.setReadOnly("cell", row, "sndClsNm", true);
                gr_retrieve.setReadOnly("cell", row, "dsmbrkBondZoneNm", true);
                gr_retrieve.setReadOnly("cell", row, "crryinPackKnd", true);
            } else {
                // 반입유형 체크 HSN 반입일시 반입개수 용도구분 Xray 탱크번호 반입사고개수 반입사고중량 포장단위 반입근거번호제외하고 readonly
                gr_retrieve.setReadOnly("cell", row, "mrn", true);
                gr_retrieve.setReadOnly("cell", row, "msn", true);
                gr_retrieve.setReadOnly("cell", row, "hsn", true);
                gr_retrieve.setReadOnly("cell", row, "divsCrryinoutClsCd", false);

                gr_retrieve.setReadOnly("cell", row, "crryinoutDtm", false);
                gr_retrieve.setReadOnly("cell", row, "crryinoutPatternCd", false);
                gr_retrieve.setReadOnly("cell", row, "crryinoutAccdPattern", false);
                gr_retrieve.setReadOnly("cell", row, "crryinoutBasisNo", false);
                gr_retrieve.setReadOnly("cell", row, "crryinoutCnt", false);

                gr_retrieve.setReadOnly("cell", row, "crryinoutWt", false);
                gr_retrieve.setReadOnly("cell", row, "crryinAccdCnt", false);
                gr_retrieve.setReadOnly("cell", row, "crryinAccdWt", false);
                gr_retrieve.setReadOnly("cell", row, "sndDtm", true);

                gr_retrieve.setReadOnly("cell", row, "sndClsNm", true);
                gr_retrieve.setReadOnly("cell", row, "dsmbrkBondZoneNm", true);
                gr_retrieve.setReadOnly("cell", row, "crryinPackKnd", false);
            }
        } else {
            // 반입유형 반입일시 반입개수 반입중량 반입사고유형 분할반입구분 용도구분 XRAY 탱크번호 반입근거번호 포장단위 
            // 반입사고개수 반입사고중량 
            gr_retrieve.setReadOnly("cell", row, "mrn", true);
            gr_retrieve.setReadOnly("cell", row, "msn", true);
            gr_retrieve.setReadOnly("cell", row, "hsn", true);
            gr_retrieve.setReadOnly("cell", row, "divsCrryinoutClsCd", false);

            gr_retrieve.setReadOnly("cell", row, "crryinoutDtm", false);
            gr_retrieve.setReadOnly("cell", row, "crryinoutPatternCd", false);
            gr_retrieve.setReadOnly("cell", row, "crryinoutAccdPattern", false);
            gr_retrieve.setReadOnly("cell", row, "crryinoutBasisNo", false);
            gr_retrieve.setReadOnly("cell", row, "crryinoutCnt", false);

            gr_retrieve.setReadOnly("cell", row, "crryinoutWt", false);
            gr_retrieve.setReadOnly("cell", row, "crryinAccdCnt", false);
            gr_retrieve.setReadOnly("cell", row, "crryinAccdWt", false);
            gr_retrieve.setReadOnly("cell", row, "sndDtm", true);

            gr_retrieve.setReadOnly("cell", row, "sndClsNm", true);
            gr_retrieve.setReadOnly("cell", row, "dsmbrkBondZoneNm", true);
            gr_retrieve.setReadOnly("cell", row, "crryinPackKnd", false);
        }
    }

    if (columnId == "autoOutYn") {
        if (ds_retrieve.getCellData(row, "crryinoutPatternCd") == "23") {
            let letAutoOutYn = ds_retrieve.getCellData(row, "autoOutYn");
            if (letAutoOutYn == "1") {
                ds_retrieve.setCellData(row, "autoOutYn", "0");
            } else {
                ds_retrieve.setCellData(row, "autoOutYn", "1");
            }
        }
    } else if (columnId == "autoOutHsn") {
        if (ds_retrieve.getCellData(row, "crryinoutPatternCd") == "23") {
            gr_retrieve.setColumnReadOnly('autoOutHsn', false);
        } else {
            gr_retrieve.setColumnReadOnly('autoOutHsn', true);
        }
    } else if (columnId == "crryinoutDeclarNo") {
        if (ds_retrieve.getCellData(row, "sndClsNm") == "오류") {
            scwin.f_errorPopUp(row);
        }
    }

    //실적정보 Setting
    ed_mblNo.setValue(ds_retrieve.getCellData(row, "mblNo"));
    ed_hblNo.setValue(ds_retrieve.getCellData(row, "hblNo"));
    ed_mcomDsmbrkPlcCd.setValue(ds_retrieve.getCellData(row, "mcomDsmbrkPlcCd"));
    ed_mcomDsmbrkPlNm.setValue(ds_retrieve.getCellData(row, "mcomDsmbrkPlcNm"));
    ed_packUnitCd.setValue(ds_retrieve.getCellData(row, "packUnitCd"));
    ed_packUnitNm.setValue(ds_retrieve.getCellData(row, "packUnitNm"));
    ed_odrNo2.setValue(ds_retrieve.getCellData(row, "odrNo"));
    ed_commCd.setValue(ds_retrieve.getCellData(row, "commCd"));
    ed_commNm.setValue(ds_retrieve.getCellData(row, "commNm"));
    ed_packCnt.setValue(ds_retrieve.getCellData(row, "packCnt"));
    ed_totWt.setValue(ds_retrieve.getCellData(row, "totWt"));
    ed_totCbm.setValue(ds_retrieve.getCellData(row, "totCbm"));
    ed_cnsgnNmCmpy.setValue(ds_retrieve.getCellData(row, "cnsgnNmCmpy"));
    ed_vsslNm.setValue(ds_retrieve.getCellData(row, "vsslNm"));
    ed_arrvlportDt.setValue(ds_retrieve.getCellData(row, "arrvlportDt"));
};

scwin.gr_retrieve_onafteredit = function (rowIndex, columnIndex, value) {
    let colid = gr_retrieve.getColumnID(columnIndex);
    switch (colid) {
        case "crryinoutDtm":
            value = $c.str.rpad(value, 14, "0");
            ds_retrieve.setCellData(rowIndex, "crryinoutDtm", value);
            break;

        case "crryinoutPatternCd":
            if (value == "23") {
                ds_retrieve.setCellData(rowIndex, "autoOutYn", "1");
                gr_retrieve.setReadOnly("cell", rowIndex, "autoOutHsn", false);
            } else {
                ds_retrieve.setCellData(rowIndex, "autoOutYn", "0");
                gr_retrieve.setReadOnly("cell", rowIndex, "autoOutHsn", true);
            }
            break;

        case "crryinoutCnt":
        case "crryinoutWt":
        case "crryinAccdCnt":
        case "crryinAccdWt":
            if ($c.util.isEmpty(value) || isNaN(value)) {
                ds_retrieve.setCellData(rowIndex, colid, "0");
            }
            break;
    }
};

