        await $c.win.alert("작업장 코드는 필수 입력 항목입니다.");
        ed_wrkPlCd.focus();
        return;
    }

    // 필수항목 체크
    if (!await $c.gus.cfValidate([tb_queryList], null, true)) {
        return;
    }

    let reportFile = "/ds/op/wrkrslts/yardwrkrslts/op_302_01_16r.ozr";
    let odiName = "op_302_01_16r";
    let mode = "";
    let odiParam = {
        "wrkPlCd": ed_wrkPlCd.getValue().trim(),
        "fromDt": crryinoutDtmFrom.getValue().trim(),
        "toDt": crryinoutDtmTo.getValue().trim(),
    }

    if (chb_previewCheck1.getValue() == "1") {
        mode = "preview";
    } else if (chb_printCheck1.getValue() == "1") {
        mode = "print";
    }

    let data = {
        odiName: odiName,
        reportName: reportFile,
        odiParam: odiParam,
        viewerParam: {
            "useprogressbar": true, // 프로그레스바 쓸지 말지
            "mode": mode,
        },
        formParam: {
        }
    };

    if (chb_previewCheck1.getValue() == "1") { // 미리보기 체크된 경우
        let opts = {
            id: "ozReportPopup",
            popupName: "오즈 리포트",
            modal: false,
            type: "browserPopup",
            width: 1000,
            height: 830,
            title: "오즈 리포트"
        };

        $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
    } else if (chb_printCheck1.getValue() == "1") { // 인쇄옵션 체크된 경우
        let opts = {
            type: 'print', // viewer, print, download
            printMode: 'view', // silent, view
        }
        $c.ext.printOzReport(data, opts);
    } else { // 저장후바로출력
        let opts = {
            filename: odiName,
            exportMode: 'view'
        }
        $c.ext.downloadOzReport(data, opts);
    }
};
